  Point legalGridPt(const Cell* cell,
                    const Point& pt,
                    int row_height = -1,
                    int site_width = -1) const;
  Point legalPt(const Cell* cell,
                bool padded,
                int row_height = -1,
                int site_width = -1) const;
  Point legalGridPt(const Cell* cell,
                    bool padded,
                    int row_height = -1,
                    int site_width = -1) const;
  Point nearestBlockEdge(const Cell* cell,
