GlobalRouter::GlobalRouter()
    : logger_(nullptr),
      stt_builder_(nullptr),
      antenna_checker_(nullptr),
      opendp_(nullptr),
      resizer_(nullptr),
      fastroute_(nullptr),
      grid_origin_(0, 0),
      groute_renderer_(nullptr),
      grid_(new Grid),
      adjustment_(0.0),
      min_routing_layer_(1),
      max_routing_layer_(-1),
      layer_for_guide_dimension_(3),
