void FrNet::reset(odb::dbNet* db_net,
                  bool is_clock,
                  int driver_idx,
                  int edge_cost,
                  int min_layer,
                  int max_layer,
                  float slack,
                  std::vector<int>* edge_cost_per_layer)
{
